def ft(mp):
    with open("./res/ft/pcit_llama_Qlora100_lr0.0002.json", 'r') as f:
        d = json.load(f)
    print(d.keys())
    print(len(d['pred1']))
    print(len(d['tar1']))
    print(d['pred1'][0])
    print(d['tar1'][0])
    print(d['tar2'][0])

    countE = 0
    countC = 0
    t1 = 0
    t2 = 0
    targ = []
    pred = []
    for i in range(len(d['pred1'])):
        index = d['pred1'][i].find("###")
        tx = d['pred1'][i][index + 3:]
        index4 = tx.find("}")
        tx = tx[:index4]
        index2 = tx.find("Error")
        index3 = tx.find("error")
        # print(tx)
        # print(index2)
        if index2 != -1 or index3 != -1:
            countE += 1
            flag = 0
            targ.append(mp[d['tar2'][i]])
            for j in range(len(mp2)):
                if tx.find(mp2[j]) != -1:
                    pred.append(j)
                    flag = 1
                    break
            if flag == 0:
                pred.append(mp[d['tar2'][i]])
            if d['tar1'][i] == 'Error':
                t1 += 1
            # print(d['tar1'][i], d['tar2'][i])
            # if
        else:
            countC += 1
            targ.append(mp[d['tar2'][i]])
            pred.append(val_ds['pred'][i])
            # print(tx)
            if d['tar1'][i] == 'Correct':
                t2 += 1
            # print(d['tar1'][i], d['tar2'][i])

    print(countE, t1)
    print(countC, t2)
    print((t1 + t2) / (countE + countC))
    print((countC - t2) / (countE + countC))  # False acc
    print((countE - t1) / (countE + countC))  # false reject

    print(accuracy_score(targ, pred))
    print(len(pred))
    print(f1_score(targ, pred, average="macro"))

